import React from 'react';

export default function Games() {
  return (
    <main>
      <h1>Games</h1>
      <p>Choose a game to play:</p>
      <ul>
        <li>Hang man 🙍‍♂️</li>
        <li>Tic tac toe ❌⭕</li>
        <li>Picture or GIF puzzle game 🧩</li>
        <li>Sound board</li>
        <li>Fun cat pictures game 😸</li>
        <li>What song matches your age?</li>
      </ul>
    </main>
  );
}
